import React, {createContext, type PropsWithChildren, type ReactNode, useRef} from 'react';
import type {IMainContextProps, IMainContextValues} from '@lmb-it/kitsconcerto-types';
import DialogProvider from '../DialogContext';
import PermissionsProvider from '../PermissionsContext';
import LocaleContextProvider from '../Locale';
import ThemeContext, {KitsThemeProvider} from '../Theme';
// import {IHeaderRef} from '../Components/Organisms/Layout/Header';
// import {AuthLayout} from '../Components';
// import AdminLayout from '../Components/Organisms/Layout/AdminLayout';
import {useWindowDimensions} from 'react-native';
import {GluestackUIProvider} from '@lmb-it/kitsconcertomobile/ui/gluestack-ui-provider';
import {DimensionsProvider} from '@lmb-it/kitsconcertomobile/Factory/DimensionsContext';

export const MainContext = createContext<IMainContextValues>({} as IMainContextValues);

export default function MainContextProvider({
                                                children,
                                                theme,
                                                kitsTheme,
                                                onLogOut,
                                                nonAuthRoutes,
                                                menuItems,
                                                permissions,
                                                logo,
                                                languages,
                                                defaultLanguage = 'en',
                                                authedRoutes,
                                                onChangeLanguage
                                            }: PropsWithChildren<IMainContextProps>) {
    const {width, height} = useWindowDimensions();

    const mq = {
        isSmall: width < 768,
        isTablet: width >= 768 && width < 1024,
        isDesktop: width >= 1024,
        isLandscape: width > height,
        isPortrait: height >= width
    };
    type IHeaderRef = any;
    const headerRef = useRef<IHeaderRef>(null);
    const appendToHeader = (element: ReactNode) => {
        if (headerRef.current?.appendToHeader) headerRef.current.appendToHeader(element);
    };


    const authLayout = !children && nonAuthRoutes?.length && !authedRoutes?.length;
    const adminLayout = !children && authedRoutes?.length && !nonAuthRoutes?.length;

    return (
        <MainContext.Provider value={{logo, onLogOut, appendToHeader, menuItems, mq}}>
            <GluestackUIProvider mode={theme}>
                <DimensionsProvider>
                    <KitsThemeProvider theme={kitsTheme}>
                        <ThemeContext theme={theme}>
                            <LocaleContextProvider
                                defaultLanguage={defaultLanguage}
                                languages={languages}
                                onChangeLanguage={onChangeLanguage}
                            >
                                <DialogProvider>
                                    <PermissionsProvider roles={permissions}>
                                        {!authLayout && !adminLayout && children}
                                        {/*{authLayout && <AuthLayout routes={nonAuthRoutes} />}*/}
                                        {/*{adminLayout && <AdminLayout routes={authedRoutes} headerRef={headerRef} />}*/}
                                    </PermissionsProvider>
                                </DialogProvider>
                            </LocaleContextProvider>
                        </ThemeContext>
                    </KitsThemeProvider>
                </DimensionsProvider>
            </GluestackUIProvider>
        </MainContext.Provider>
    );
}
